        if(level === 0) {
            usedKey = SCATTER_ANIMATION_PREFAB_KEY0;
        } else if(level === 1) {
            usedKey = SCATTER_ANIMATION_PREFAB_KEY1;
        } else if(level === 2) {
            usedKey = SCATTER_ANIMATION_PREFAB_KEY2;
        }
        scatterEnterAnimationNode = PrefabPoolManager.GetInstance().GetNode(usedKey);
        if (!scatterEnterAnimationNode) {
            return;
        }
        scatterEnterAnimationNode['_prefabKey'] = usedKey;

        // 取得 Spine 組件
        scatterSpine = scatterEnterAnimationNode.getComponent(BaseSpine);
        if (!scatterSpine) {
            PrefabPoolManager.GetInstance().ReturnNode(
                usedKey,
                scatterEnterAnimationNode
            );
            return;
        }

        // 設定父節點
        scatterEnterAnimationNode.setParent(this.m_effectNodes[Game_Define.LAYERS.SYMBOL]);

        // 存儲 Spine 到 Map
        this.m_scatterAnimationSpines.set(position, scatterSpine);
    }

    // 設定位置（無論新建或復用都需要設定）
    scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));

    // 顯示節點
    scatterSpine.node.active = true;

    // Spine初始化完成，呼叫回調
    if (onSpineReady) {
        onSpineReady(scatterSpine);
    }

    if(level === 0) {
        await scatterSpine.PlayAnimation(
            SCATTER_WIN_ANIMATION_SPINE_KEY_LV0,
            scatterSpine.Spine,
            false
        );
    } else if(level === 1) {
        await scatterSpine.PlayAnimation(
            SCATTER_WIN_ANIMATION_SPINE_KEY_LV1,
            scatterSpine.Spine,
            false
        );
    } else if(level === 2) {
        await scatterSpine.PlayAnimation(
            SCATTER_WIN_ANIMATION_SPINE_KEY_LV2,
            scatterSpine.Spine,
            false
        );
    }

    // Win/Collect 動畫播完後接 Idle loop，防止動畫結束後 spine 視覺消失造成空窗
    if (!isLoop && scatterSpine && scatterSpine.node.active) {
        scatterSpine.PlayAnimation(
            SCATTER_IDLE_ANIMATION_SPINE_KEY,
            scatterSpine.Spine,
            true
        );
    }
}

