 * @ch 獲取Scatter進入動畫Spine
 * @param position 位置
 * @returns Scatter進入動畫Spine
 */
GetScatterEnterAnimationSpine(position: number) : BaseSpine {
    if (!this.m_scatterAnimationSpines.has(position)) {
        return null;
    }
    return this.m_scatterAnimationSpines.get(position);
}

/**
 * @ch 取得所有 Scatter 動畫 Spine 的 map
 */
GetAllScatterAnimationSpines(): Map<number, BaseSpine> {
    return this.m_scatterAnimationSpines;
}

/**@ch 檢查某個 Spine 是否還在 map 中（值比對）*/
HasScatterSpineInMap(spine: BaseSpine): boolean {
    for (const [_, s] of this.m_scatterAnimationSpines) {
        if (s === spine) return true;
    }
    return false;
}

/**@ch 用暫時 key 把 Spine 加回 map（RebuildScatterAnimationSpinesKeys 會修正 key）*/
AddScatterSpineToMap(spine: BaseSpine) {
    // 用負數遞減 key 避免衝突
    let tempKey = -1;
    while (this.m_scatterAnimationSpines.has(tempKey)) tempKey--;
    this.m_scatterAnimationSpines.set(tempKey, spine);
}

/**
 * @ch 根據 Scatter 特效節點的當前世界座標重建 map key
 */
RebuildScatterAnimationSpinesKeys() {
    const newMap = new Map<number, BaseSpine>();
    for (const [_, spine] of this.m_scatterAnimationSpines) {
        if (spine && spine.node.active) {
            const worldPos = spine.node.getWorldPosition();
            // 找最近的格子位置
            for (let col = 0; col < Game_Define.COL; col++) {
                const visibleCount = this.m_gameView.SlotReels.GetVisibleSymbolCount(col);
                for (let row = 0; row < visibleCount; row++) {
                    const cellPos = this.GetSymbolNodeWorldPos(col, row);
                    if (Math.abs(cellPos.x - worldPos.x) < 30 && Math.abs(cellPos.y - worldPos.y) < 30) {
                        const newKey = Common.GetPositionFromColRow(col, row);
                        newMap.set(newKey, spine);
                    }
                }
            }
        }
    }
    this.m_scatterAnimationSpines = newMap;
}

