import { _decorator, log, warn, tween } from "cc";
import { stateManager, BaseState, eventManager } from "db://astarte-framework/Managers";
import { Define } from "db://astarte-framework/utilis";
import GameView from "../GameView";
import Game_Define, { FeaturePosQueueType } from "../Game_Define";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { AudioManager } from "../Audio/AudioManager";
import { Common } from "../Common/Common";
import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CANNON_ANIM_NAME, CHARACTER_ANIM_NAME } from "../BSSpineCtrl";

const { ccclass } = _decorator;
@ccclass( "AddFreeState" )
export class AddFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : AddFreeState" );
        // AudioManager.Play(AudioManager.AudioClips.FG_Add);

        // 停輪後等 1 秒再開始 +SPIN 演出
        await Define.Wait( this.m_gameView, 1.0 );

        let roundInfo = this.m_gameView.RoundInfo;
        let addRound = roundInfo.FeverTotalRound - this.m_gameView.FreeTotalRound;

        // 播放 Scatter Collect 動畫
        const positions = this.GetScatterPositions();
        const scatterLevel = this.m_gameView.HasScatterBoost ? 2 : 1;

        // 整段 collect 演出只播一次 Scatter 觸發音效（避免多顆 scatter 同步疊播）
        if ( positions.length > 0 )
        {
            AudioManager.Play(AudioManager.AudioClips.FG_Scatter_trigger);
        }

        let winPromises: Promise<void>[] = [];
        for ( const pos of positions )
        {
            const { col, row } = Common.GetColRowFromPosition( pos );

            this.m_gameView.SlotReels.SetSymbolShow( col, row, false );
            const animPromise = this.m_gameView.EffectPlate.PlayScatterWinAnimation( scatterLevel, col, row, true );
            // 3秒 timeout 防禦：避免 Spine 動畫卡死導致整個 state 卡住
            const timeoutPromise = Define.Wait( this.m_gameView, 3 ).then( () => {} );
            winPromises.push( Promise.race( [ animPromise, timeoutPromise ] ) );
        }
        if ( winPromises.length === 0 )
        {

        }
        await Promise.all( winPromises );

        // Scatter Collect 演出結束後等 0.5 秒再跳出加局宣告
        await Define.Wait( this.m_gameView, 0.5 );

        // 顯示加局宣告面板
        AudioManager.Play(AudioManager.AudioClips.FG_Win_on);
        await Promise.race( [
            this.m_gameView.PopupBoard.ShowMoreSpinsDeclare( addRound ),
            new Promise<void>( r => Define.Wait( this.m_gameView, 3 ).then( () => { warn( "[AddFreeState] WARNING: ShowMoreSpinsDeclare TIMEOUT" ); r(); } ) )
        ] );

        // 看板出現後再停 0.5 秒
        await Define.Wait( this.m_gameView, 0.5 );

        // 加手數光拖尾：面板 → 剩餘手數計數器（PlayAddSpinFly 永遠 resolve，不擋流程）
        console.log("[DEBUG][AddFreeState] 到達拖尾呼叫點, addRound =", addRound,
            ", AddSpinFlyEffect =", this.m_gameView.AddSpinFlyEffect);
        await this.m_gameView.AddSpinFlyEffect?.PlayAddSpinFly();

        // 拖尾落點後才更新加局數（不做倒數演出）
        this.m_gameView.FreeTotalRound += addRound;
        eventManager.Dispatch(
            FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND,
            roundInfo.FeverNowRound,
            this.m_gameView.FreeTotalRound
        );

        // 角色+砲台 Win2 加局慶祝
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, CHARACTER_ANIM_NAME.Win0, false);
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, CANNON_ANIM_NAME.Win2, false);

