      * @param {boolean} [isLoop=false] 是否循環播放
      * @param {number} [timeScale=Game_Define.SpeedUp] 播放速度縮放
      * @param {(eventName: string) => void} [eventCb] 動畫事件回呼
      * @param {number} [trackIdx=0] 軌道索引
      * @returns {Promise<boolean>} 動畫成功開始播放回傳 true，否則回傳 false
      */
    PlayAnimation(
        animName: string,
        target = this.m_spine,
        isLoop: boolean = false,
        timeScale: number = Game_Define.SpeedUp,
        eventCb?: ( eventName: string ) => void,
        trackIdx: number = 0
    ) : Promise<boolean>
    {
        // 檢查 Spine 骨骼資料是否存在
        if (!target.skeletonData) {
            console.warn(`[BaseSpine] Spine skeleton data is null for animation: ${animName}`);
            return Promise.resolve(false);
        }

        // 檢查動畫是否存在於骨骼資料中
        const skeletonData = target.skeletonData.getRuntimeData();
        if (skeletonData) {
            const hasAnimation = skeletonData.animations.find((anim: any) => anim.name === animName);
            if (!hasAnimation) {
                console.warn(`[BaseSpine] Animation "${animName}" not found in spine: ${target.node.name}`);
                return Promise.resolve(false);
            }
        } else {
            console.warn(`[BaseSpine] getRuntimeData() is null for animation: ${animName}, spine: ${target.node.name}`);
            return Promise.resolve(false);
        }

        // 設定時間縮放
        target.timeScale = timeScale;

        target.clearTrack( trackIdx );
        target.setToSetupPose();

        // 使用 SpineKit 播放動畫，trackIdx 設為 0
        return SpineKit.PlayAnimation(
            target,
            animName,
            isLoop,
            trackIdx, // trackIdx
            eventCb
        );
    }
}

