    // Silver/Gold（Collect）：播完凍結在最後一個 frame（timeScale=0），
    // 停留到既有清理流程（StopAllScatterAnimation / 節點回收）才移除
    if (scatterSpine && scatterSpine.node.active && scatterSpine.Spine) {
        scatterSpine.Spine.timeScale = 0;
